function badge(t,c=""){return `<span class="badge ${c}">${t}</span>`}
function titulo(id){return (pantallas.find(p=>p.id===id)||{label:"Panel principal"}).label}
function ayuda(id){return `<article class="card module-help"><span class="eyebrow">Ayuda rápida</span><h3>${titulo(id)}</h3><p>${ayudas[id]||"Esta sección te ayuda a tomar mejores decisiones."}</p></article>`}
function tabla(cols,rows){return `<article class="table-card"><table class="table"><thead><tr>${cols.map(c=>`<th>${c}</th>`).join("")}</tr></thead><tbody>${rows.map(r=>`<tr>${r.map(x=>`<td>${x}</td>`).join("")}</tr>`).join("")}</tbody></table></article>`}
function metricas(){return `<div class="grid metrics">${datos.metricas.map(([a,b,c])=>`<article class="card metric-card"><small>${a}</small><span class="metric-value">${b}</span><span class="delta">${c}</span></article>`).join("")}</div>`}
function mundo(){return `<article class="card world-panel"><span class="eyebrow">Mapa de señales</span><h3>Oportunidades por país, idioma y nicho</h3><p class="muted">Vista simulada para entender dónde conviene crear contenido.</p><div class="world-map"><i class="arc" style="left:18%;top:40%;width:220px;transform:rotate(-10deg)"></i><i class="arc" style="left:34%;top:56%;width:260px;transform:rotate(-20deg)"></i><span class="signal" style="left:18%;top:38%"></span><span class="signal green" style="left:31%;top:61%"></span><span class="signal amber" style="left:55%;top:34%"></span><span class="signal green" style="left:72%;top:53%"></span><span class="world-label">MUNDO</span></div></article>`}
function estado(){return `<article class="card"><span class="eyebrow">Estado</span><h3>Operación clara y segura</h3>${[["Backend","Conectado en modo local","OK"],["IA real","Pendiente para fases futuras","Planificado"],["Publicación","Sin envíos reales","Seguro"],["Contenido","Demostración responsable","Activo"]].map(([a,b,c])=>`<div class="status-row"><div><span class="status-name">${a}</span><span class="status-meta">${b}</span></div>${badge(c,c==="OK"||c==="Activo"?"ok":"info")}</div>`).join("")}</article>`}
function inicio(){return `<section class="welcome-panel"><span class="eyebrow">AppFactoryChile</span><h2>Bienvenido a APP FACTORY VIDEO IA</h2><p>¿Qué deseas hacer hoy?</p><div class="quick-actions"><button class="primary-btn" data-go="channels">Crear un canal</button><button class="primary-btn" data-go="mvp-workflow">Crear contenido</button><button class="ghost-btn" data-go="projects">Continuar proyecto</button><button class="ghost-btn" data-go="videos">Biblioteca</button></div></section>${metricas()}<div class="grid two">${mundo()}${estado()}</div>`}
function radar(){return `<article class="card radar-card"><span class="eyebrow">Radar</span><h3>Temas con mayor oportunidad</h3><div class="radar"><span class="ring r1"></span><span class="ring r2"></span><span class="ring r3"></span><span class="sweep"></span><i class="radar-dot d0"><b>MX</b></i><i class="radar-dot d1"><b>BR</b></i><i class="radar-dot d2"><b>CL</b></i><i class="radar-dot d3"><b>ES</b></i></div></article>`}
function ideas(){return `<article class="card"><span class="eyebrow">Laboratorio de Ideas</span><h3>Ideas antes de producir</h3>${datos.ideas.map(([a,b,c,d])=>`<div class="entity-row"><div><span class="entity-title">${a}</span><span class="entity-meta">Emoción: ${c}. Potencial: ${d}.</span></div>${badge(`${b}/100`,"ok")}</div>`).join("")}</article>`}
function hooks(){return `<article class="card"><span class="eyebrow">Constructor de Hooks</span><h3>Compara inicios posibles</h3><div class="hook-stack">${datos.hooks.map(([a,b])=>`<div class="hook-card"><strong>${a}</strong><span>${b}</span></div>`).join("")}</div></article>`}
function historia(){return `<article class="card director-panel"><span class="eyebrow">Director de Historias</span><h3>Estrategia narrativa recomendada</h3>${[["Objetivo","Explicar una oportunidad de forma simple y útil."],["Narrador","Voz natural, cercana y experta."],["Personaje","Persona realista enfrentando un problema concreto."],["Escenario","Ambiente visual limpio y reconocible."],["Tono","Claro, curioso y responsable."],["Duración","38 segundos."],["Estilo","Oscuro premium con subtítulos dinámicos."]].map(([a,b])=>`<div class="director-row"><span>${a}</span><strong>${b}</strong></div>`).join("")}</article>`}
function plan(){return `<article class="card"><span class="eyebrow">Plan de Producción</span><h3>Cómo debería verse el video</h3>${[["Narrador","Natural y confiable"],["Tipo de voz","Cálida, clara y segura"],["Formato","Vertical 9:16"],["Plataformas","Shorts, Reels y TikTok"],["Música","Moderna, suave y sin derechos"],["Iluminación","Contraste premium"],["Cámara","Movimientos lentos y cortes limpios"],["Color","Base oscura con acentos cian"],["Ritmo","Inicio rápido, explicación clara y cierre breve"]].map(([a,b])=>`<div class="director-row"><span>${a}</span><strong>${b}</strong></div>`).join("")}</article>`}
function aprendizaje(){return `<div class="grid four">${[["Hooks probados","1.284"],["Ideas analizadas","8.420"],["Países aprendiendo","38"],["Mejoras detectadas","126"]].map(([a,b])=>`<article class="card metric-card"><small>${a}</small><span class="metric-value">${b}</span><span class="delta">Aprendizaje acumulado</span></article>`).join("")}</div><article class="card"><h3>Recomendaciones aprendidas</h3>${["Las introducciones cortas retienen mejor.","Los ejemplos locales aumentan comentarios.","La utilidad clara supera al volumen de publicaciones.","La narración cálida funciona mejor para contenido educativo."].map(t=>`<div class="entity-row"><div><span class="entity-title">${t}</span><span class="entity-meta">Principio general, no copia de contenido.</span></div>${badge("Aprendido","ok")}</div>`).join("")}</article>`}
function flujoContenido(){const pasos=["Oportunidad","Investigación","Ideas","Ranking","Hook","Historia","Guion gráfico","Plan","Listo"];return `<article class="card"><span class="eyebrow">Flujo de Contenido</span><h3>De la oportunidad al contenido listo</h3><div class="pipeline-flow">${pasos.map((p,i)=>`<div class="flow-step"><span class="flow-index">${String(i+1).padStart(2,"0")}</span><strong>${p}</strong><small>Responsable: IA editorial</small>${badge("Preparado","ok")}</div>`).join("")}</div></article>`}
function proceso(){return `<article class="card"><span class="eyebrow">Proceso del Video</span><h3>Recorrido completo</h3><div class="decision-timeline">${["Idea","Investigación","Guion","Guion gráfico","Narración","Subtítulos","Render","Programación","Analítica","Aprendizaje"].map((p,i)=>`<div class="timeline-item"><time>${String(i+1).padStart(2,"0")}</time><div><strong>${p}</strong><p>Etapa preparada para fases futuras.</p></div></div>`).join("")}</div></article>`}
function produccion(){return `<article class="card"><span class="eyebrow">Producción en Tiempo Real</span><h3>Cola simulada</h3>${["Idea en revisión","Hook seleccionado","Guion gráfico preparado","Plan de producción listo"].map((p,i)=>`<div class="queue-row"><div><span class="entity-title">Contenido ${String(i+1).padStart(3,"0")}</span><span class="entity-meta">${p}</span><div class="progress-track"><div class="progress-fill" style="width:${45+i*15}%"></div></div></div>${badge("Demostración","info")}</div>`).join("")}</article>`}
function pantalla(id){const contenido={"global-intelligence":`${mundo()}${tabla(["País","Tema","Idioma","Competencia","Demanda","Horario","Nivel"],datos.oportunidades)}`,"opportunity-radar":`${radar()}${tabla(["País","Nicho","Idioma","Competencia","Potencial","Hora","Nivel"],datos.oportunidades)}`,"learning-engine":aprendizaje(),"story-director":historia(),"idea-lab":ideas(),"hook-builder":hooks(),"content-brain":`<div class="grid two"><article class="card"><span class="eyebrow">Cerebro de Contenido</span><h3>Antes de crear, el sistema razona</h3><p>Analiza oportunidad, investigación, ideas, clasificación, audiencia, hooks, estrategia narrativa y plan de producción.</p>${badge("Conectado","info")}</article>${ideas()}</div>`,"content-pipeline":flujoContenido(),"production-plan":plan(),"full-video-journey":proceso(),calendar:tabla(["Zona","País","Idioma","Hora ideal","Pendientes"],[["América","México","Español","13:00","12"],["Europa","España","Español","21:00","8"],["Brasil","Brasil","Portugués","08:00","10"]]),monetization:metricas(),"video-factory-live":produccion(),"digital-factory":`<div class="grid two">${produccion()}${flujoContenido()}</div>`,channels:tabla(["Canal","País","Idioma","Nicho","Estado"],datos.canales.map(r=>[r[0],r[1],r[2],r[3],badge(r[4],r[4]==="Activo"?"ok":"warn")])),settings:`<article class="card"><span class="eyebrow">Configuración</span><h3>Preferencias iniciales</h3><div class="form-grid">${["Idioma de la interfaz","Zona horaria","Modo de revisión","Publicación automática","Proveedor IA","Cumplimiento"].map(t=>`<div class="field"><label>${t}</label><input readonly value="Preparado para configurar" /></div>`).join("")}</div></article>`,apis:tabla(["Servicio","Uso futuro","Estado"],[["YouTube","Publicación y métricas oficiales",badge("Pendiente","warn")],["Instagram","Reels y métricas oficiales",badge("Pendiente","warn")],["Facebook","Video y páginas",badge("Pendiente","warn")],["TikTok","Publicación oficial",badge("Pendiente","warn")]]),"mission-control":`${metricas()}<div class="grid two">${estado()}${produccion()}</div>`,system:`${estado()}${metricas()}`,company:`<article class="card"><span class="eyebrow">Empresa matriz</span><h3>AppFactoryChile</h3><p>Correo principal: appfactorychile@gmail.com</p><p class="muted">Proyecto oficial: APP FACTORY VIDEO IA.</p></article>`,projects:tabla(["Proyecto","Canal","Estado","Último paso"],[["IA para pymes","Futuro Latino IA",badge("En curso","info"),"Plan de producción"],["Ahorro energético","Brasil Solar",badge("Borrador","warn"),"Ideas"]]),videos:`<div class="video-grid">${["Idea","Guion","Guion gráfico","Plan","Proyecto","Canal","Hook","Informe"].map((t,i)=>`<article class="card video-card"><div class="thumb">${String(i+1).padStart(2,"0")}</div><div class="video-card-body"><h3>${t}</h3><p class="muted">Elemento preparado en modo demostración.</p>${badge("Biblioteca","info")}</div></article>`).join("")}</div>`,agents:tabla(["Agente","Función","Estado"],[["Analista IA","Detecta oportunidades",badge("Activo","ok")],["Guionista IA","Prepara historias",badge("Activo","ok")],["Editor IA","Planifica producción",badge("Planificado","info")]])};return `${ayuda(id)}${contenido[id]||`<article class="card"><h3>${titulo(id)}</h3><p>Sección preparada para siguientes fases.</p></article>`}`}
function postFlujo(ruta,cuerpo){return fetch(`${API_BASE}${ruta}`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(cuerpo)}).then(r=>{if(!r.ok)throw new Error(UI.error);return r.json()})}
function sync(r){estadoFlujo.workflowId=r.workflow_id||estadoFlujo.workflowId;estadoFlujo.progreso=r.progress||estadoFlujo.progreso;estadoFlujo.estado="listo";estadoFlujo.error=""}
function datosCanal(){const v=id=>document.getElementById(id)?.value.trim()||"";const modo=document.querySelector('input[name="workflowMode"]:checked')?.value||"manual";return{name:v("wfName"),country:v("wfCountry"),language:v("wfLanguage"),niche:v("wfNiche"),description:v("wfDescription"),daily_video_count:Number(v("wfDailyVideos")||8),platforms:v("wfPlatforms").split(",").map(x=>x.trim()).filter(Boolean),mode:modo}}
async function accionFlujo(accion,p={}){try{estadoFlujo.estado="cargando";estadoFlujo.error="";renderScreen("mvp-workflow");let r;if(accion==="create-channel"){r=await postFlujo("/api/workflow/create-channel",datosCanal());sync(r);estadoFlujo.canal=r.channel}if(accion==="analyze-opportunity"){r=await postFlujo("/api/workflow/analyze-opportunity",{workflow_id:estadoFlujo.workflowId});sync(r);estadoFlujo.oportunidad=r}if(accion==="generate-ideas"){r=await postFlujo("/api/workflow/generate-ideas",{workflow_id:estadoFlujo.workflowId});sync(r);estadoFlujo.ideas=r.ideas}if(accion==="choose-idea"){r=await postFlujo("/api/workflow/choose-idea",{workflow_id:estadoFlujo.workflowId,idea_id:p.ideaId});sync(r);estadoFlujo.ideaElegida=r.selected_idea}if(accion==="generate-hooks"){r=await postFlujo("/api/workflow/generate-hooks",{workflow_id:estadoFlujo.workflowId});sync(r);estadoFlujo.hooks=r.hooks}if(accion==="choose-hook"){r=await postFlujo("/api/workflow/choose-hook",{workflow_id:estadoFlujo.workflowId,hook_id:p.hookId});sync(r);estadoFlujo.hookElegido=r.selected_hook}if(accion==="generate-story"){r=await postFlujo("/api/workflow/generate-story",{workflow_id:estadoFlujo.workflowId});sync(r);estadoFlujo.historia=r}if(accion==="generate-production-plan"){r=await postFlujo("/api/workflow/generate-production-plan",{workflow_id:estadoFlujo.workflowId});sync(r);estadoFlujo.plan=r}if(accion==="ready-to-generate"){r=await postFlujo("/api/workflow/ready-to-generate",{workflow_id:estadoFlujo.workflowId});sync(r);estadoFlujo.listo=r}renderScreen("mvp-workflow")}catch(e){estadoFlujo.estado="error";estadoFlujo.error=e.message;renderScreen("mvp-workflow")}}
function barra(){const pasos=[["channel","Canal"],["opportunity","Oportunidad"],["ideas","Ideas"],["idea_selected","Idea"],["hooks","Hook"],["storyboard","Guion gráfico"],["production","Producción"],["ready","Listo"]];return `<article class="card workflow-progress"><span class="eyebrow">Flujo guiado</span><h3>Avanza paso a paso</h3><div class="workflow-steps">${pasos.map(([k,l])=>`<span class="${estadoFlujo.progreso[k]?"done":""}">${l} ${estadoFlujo.progreso[k]?"✓":""}</span>`).join("")}</div>${estadoFlujo.error?`<p class="muted workflow-error">${estadoFlujo.error}</p>`:""}</article>`}
function formCanal(){return `<article class="card"><span class="eyebrow">Paso 1</span><h3>Crear canal</h3><div class="form-grid"><div class="field"><label>Nombre</label><input id="wfName" value="Futuro Latino IA" /></div><div class="field"><label>País</label><input id="wfCountry" value="México" /></div><div class="field"><label>Idioma</label><input id="wfLanguage" value="Español" /></div><div class="field"><label>Nicho</label><input id="wfNiche" value="Tecnología" /></div><div class="field"><label>Videos diarios</label><input id="wfDailyVideos" type="number" value="8" /></div><div class="field"><label>Plataformas</label><input id="wfPlatforms" value="YouTube Shorts, Instagram Reels, TikTok" /></div><div class="field workflow-span"><label>Descripción</label><input id="wfDescription" value="Herramientas de IA para pequeñas empresas" /></div><div class="field"><label>Modo</label><div class="mode-toggle"><label><input type="radio" name="workflowMode" value="automatic" /> Automático</label><label><input type="radio" name="workflowMode" value="manual" checked /> Manual</label></div></div></div><button class="primary-btn" data-workflow-action="create-channel">Guardar canal</button></article>`}
function ideasFlujo(){return estadoFlujo.ideas.map((x,i)=>`<article class="workflow-choice ${estadoFlujo.ideaElegida?.id===x.id?"selected":""}"><strong>${["La razón oculta por la que esta herramienta importa ahora","Cómo ahorrar una hora usando IA de forma simple","Lo que muchos entienden mal sobre la IA","Una historia local sobre IA para pequeñas empresas","Antes de ignorar esta tendencia, mira esto","La prueba de 3 segundos para entender la oportunidad","Por qué los creadores hablan de este tema","La forma segura de probar esta idea","El detalle pequeño que cambia todo","Qué viene después en esta tendencia"][i]||"Idea recomendada"}</strong><p>Promesa clara, útil y responsable para el público del canal.</p><div class="style-meta"><span>Curiosidad ${x.curiosity}</span><span>Nivel viral ${x.viral_level}</span><span>Monetización ${x.monetization}</span><span>Retención ${x.retention}</span></div><button class="ghost-btn" data-workflow-action="choose-idea" data-idea-id="${x.id}">Elegir idea</button></article>`).join("")}
function hooksFlujo(){return estadoFlujo.hooks.map((x,i)=>`<div class="hook-card ${estadoFlujo.hookElegido?.id===x.id?"selected":""}"><strong>${datos.hooks[i]?.[0]||"Hook recomendado"}</strong><span>${x.score}/100</span><small>Alta retención esperada</small><button class="ghost-btn" data-workflow-action="choose-hook" data-hook-id="${x.id}">Seleccionar hook</button></div>`).join("")}
function pantallaFlujo(){return `${ayuda("mvp-workflow")}${barra()}${formCanal()}${estadoFlujo.canal?`<article class="card"><span class="eyebrow">Paso 2</span><h3>Analizar oportunidad</h3>${estadoFlujo.oportunidad?`<div class="grid four"><article class="metric-card"><small>Nivel de oportunidad</small><span class="metric-value">${estadoFlujo.oportunidad.opportunity_score}</span></article><article class="metric-card"><small>Competencia</small><span class="metric-value">Media</span></article><article class="metric-card"><small>Potencial</small><span class="metric-value">Alto</span></article><article class="metric-card"><small>Horario ideal</small><span class="metric-value">13:00</span></article></div>`:`<p class="muted">El Cerebro de Contenido analizará el canal guardado.</p>`}<button class="primary-btn" data-workflow-action="analyze-opportunity">Analizar oportunidad</button></article>`:""}${estadoFlujo.oportunidad?`<article class="card"><span class="eyebrow">Pasos 3 y 4</span><h3>Generar y elegir idea</h3>${estadoFlujo.ideas.length?`<div class="workflow-idea-grid">${ideasFlujo()}</div>`:`<p class="muted">Genera 10 ideas y selecciona una.</p>`}<button class="primary-btn" data-workflow-action="generate-ideas">Generar 10 ideas</button></article>`:""}${estadoFlujo.ideaElegida?`<article class="card"><span class="eyebrow">Paso 5</span><h3>Generar hook</h3>${estadoFlujo.hooks.length?`<div class="hook-stack">${hooksFlujo()}</div>`:`<p class="muted">Genera 5 opciones de inicio para la idea elegida.</p>`}<button class="primary-btn" data-workflow-action="generate-hooks">Generar hooks</button></article>`:""}${estadoFlujo.hookElegido?`<article class="card"><span class="eyebrow">Pasos 6 y 7</span><h3>Estrategia narrativa y storyboard</h3>${estadoFlujo.historia?`${historia()}<div class="scene-grid">${[1,2,3,4].map(n=>`<article class="scene-card"><span>Escena ${n}</span><strong>${["Problema principal","Ejemplo local","Comparación simple","Cierre con llamada a la acción"][n-1]}</strong><p>${["Abrimos con una pregunta clara.","Mostramos la idea con un caso concreto.","Explicamos el beneficio sin exagerar.","Invitamos a conversar de forma responsable."][n-1]}</p><small>Subtítulo breve y claro.</small></article>`).join("")}</div>`:`<p class="muted">Genera objetivo, narrador, personaje, escenario, tono, duración, estilo y storyboard.</p>`}<button class="primary-btn" data-workflow-action="generate-story">Generar estrategia narrativa</button></article>`:""}${estadoFlujo.historia?`<article class="card"><span class="eyebrow">Paso 8</span><h3>Plan de producción</h3>${estadoFlujo.plan?plan():`<p class="muted">Define narrador, voz, formato, música, iluminación, cámara, color y ritmo.</p>`}<button class="primary-btn" data-workflow-action="generate-production-plan">Generar plan de producción</button></article>`:""}${estadoFlujo.plan?`<article class="card ready-card"><span class="eyebrow">Paso 9</span><h3>${estadoFlujo.listo?"Todo está listo para generar el video.":"Listo para generar el video"}</h3><p>No se generará video todavía. El proyecto queda preparado para una fase futura.</p>${estadoFlujo.listo?badge("Listo","ok"):`<button class="primary-btn" data-workflow-action="ready-to-generate">Marcar como listo</button>`}</article>`:""}`}
const pageTitle=document.getElementById("pageTitle"),sideNav=document.getElementById("sideNav"),toast=document.getElementById("toast"),sidebar=document.querySelector(".sidebar"),view=document.getElementById("view");
function renderScreen(id){const normal=alias[id]||id||"inicio";const p=pantallas.find(x=>x.id===normal)||pantallas[0];pageTitle.textContent=p.label;document.querySelectorAll(".nav-link").forEach(a=>a.classList.toggle("active",a.dataset.id===p.id));view.innerHTML=p.id==="inicio"?inicio():p.id==="mvp-workflow"?pantallaFlujo():pantalla(p.id);bindActions()}
function bindActions(){document.querySelectorAll("[data-soon]").forEach(b=>b.addEventListener("click",()=>{toast.textContent=UI.pronto;toast.classList.add("show");setTimeout(()=>toast.classList.remove("show"),1500)}));document.querySelectorAll("[data-go]").forEach(b=>b.addEventListener("click",()=>location.hash=b.dataset.go));document.querySelectorAll("[data-workflow-action]").forEach(b=>b.addEventListener("click",()=>accionFlujo(b.dataset.workflowAction,{ideaId:b.dataset.ideaId,hookId:b.dataset.hookId})))}
function buildNav(){sideNav.innerHTML=categorias.map(([nombre,items])=>`<div class="nav-group"><span>${nombre}</span>${items.map(([id,label,icon,kpi])=>`<a class="nav-link" href="#${id}" data-id="${id}" title="${label}"><span class="nav-icon">${icon}</span><span>${label}</span><small class="nav-kpi">${kpi}</small></a>`).join("")}</div>`).join("")}
function route(){renderScreen(location.hash.replace("#","")||"inicio");sidebar.classList.remove("open")}
document.getElementById("menuToggle").addEventListener("click",()=>sidebar.classList.toggle("open"));window.addEventListener("hashchange",route);buildNav();route();

